  8→/**
  9→ * OkHttp Interceptor that returns pre-recorded GitHub API responses.
 10→ * <p>
 11→ * Intercepts requests to api.github.com and returns mock data from
 12→ * src/main/resources/mock-responses/ directory.
 13→ * </p>
 14→ * <p>
 15→ * Supported endpoints: GET /orgs/{org}/repos returns {org}_repos.json,
 16→ * GET /repos/{org}/{repo}/contributors returns {org}/{repo}_contributors.json.
 17→ * </p>
 18→ */
 19→public class MockGitHubInterceptor implements Interceptor {
 20→
 21→    private static final Pattern REPOS_PATTERN =
 22→        Pattern.compile("/orgs/([^/]+)/repos");
 23→    private static final Pattern CONTRIBUTORS_PATTERN =
 24→        Pattern.compile("/repos/([^/]+)/([^/]+)/contributors");
 25→
 26→    private final String mockDataDir;
 27→
 28→    public MockGitHubInterceptor() {
 29→        // Default to classpath resources
 30→        this.mockDataDir = null;
 31→    }
 32→
 33→    public MockGitHubInterceptor(String mockDataDir) {
 34→        this.mockDataDir = mockDataDir;
 35→    }
 36→
 37→    @Override
 38→    public Response intercept(Chain chain) throws IOException {
 39→        Request request = chain.request();
 40→        String path = request.url().encodedPath();
 41→
 42→        // Try to match repos endpoint
 43→        Matcher reposMatcher = REPOS_PATTERN.matcher(path);
 44→        if (reposMatcher.matches()) {
 45→            String org = reposMatcher.group(1);
 46→            String json = loadMockData(org + "_repos.json");
 47→            if (json != null) {
 48→                return createMockResponse(request, json);
 49→            }
 50→        }
 51→
 52→        // Try to match contributors endpoint
 53→        Matcher contribMatcher = CONTRIBUTORS_PATTERN.matcher(path);
 54→        if (contribMatcher.matches()) {
 55→            String org = contribMatcher.group(1);
 56→            String repo = contribMatcher.group(2);
 57→            String json = loadMockData(org + "/" + repo + "_contributors.json");
 58→            if (json != null) {
 59→                return createMockResponse(request, json);
 60→            }
 61→        }
 62→
 63→        // No mock data found - return empty array
 64→        System.err.println("MockGitHubInterceptor: No mock data for " + path);
 65→        return createMockResponse(request, "[]");
 66→    }
 67→
 68→    private String loadMockData(String filename) {
 69→        try (InputStream is = openMockDataStream(filename)) {
 70→            if (is == null) {
 71→                return null;
 72→            }
 73→            try (BufferedReader reader = new BufferedReader(
 74→                    new InputStreamReader(is, StandardCharsets.UTF_8))) {
 75→                StringBuilder sb = new StringBuilder();
 76→                String line;
 77→                while ((line = reader.readLine()) != null) {
 78→                    sb.append(line).append("\n");
 79→                }
 80→                return sb.toString();
 81→            }
 82→        } catch (IOException e) {
 83→            System.err.println("MockGitHubInterceptor: Error loading " + filename + ": " + e.getMessage());
 84→            return null;
 85→        }
 86→    }
 87→
 88→    private InputStream openMockDataStream(String filename) throws IOException {
 89→        if (mockDataDir != null) {
 90→            File file = new File(mockDataDir, filename);
 91→            if (!file.exists()) {
 92→                return null;
 93→            }
 94→            return new FileInputStream(file);
 95→        } else {
 96→            return getClass().getResourceAsStream("/mock-responses/" + filename);
 97→        }
 98→    }
 99→
100→    private Response createMockResponse(Request request, String json) {
101→        return new Response.Builder()
102→            .request(request)
103→            .protocol(Protocol.HTTP_1_1)
104→            .code(200)
105→            .message("OK")
106→            .body(ResponseBody.create(MediaType.parse("application/json"), json))
107→            .build();
108→    }
109→}
